examples.original_ir:
define i32 @test(i32 %a, i1 %c, i32 %x) {
  %sub = sub nsw i32 0, %x
  %sel = select i1 %c, i32 %x, i32 %sub
  %res = sub i32 %a, %sel
  ret i32 %res
}

examples.optimized_ir:
define i32 @test(i32 %a, i1 %c, i32 %x) {
  %sub = sub nsw i32 0, %x
  %sel = select i1 %c, i32 %sub, i32 %x
  %res = add i32 %a, %sel
  ret i32 %res
}
